import { Mastra } from "@mastra/core";
import { openai } from "@ai-sdk/openai";
import { Agent } from "@mastra/core/agent";

const agent = new Agent({
  name: "Assistant",
  instructions: "You are a helpful assistant.",
  model: openai("gpt-4o"),
});

const mastra = new Mastra({ agents: { assistant: agent } });

const result = await mastra.getAgent("assistant").generate(
  "What is the capital of France?"
);
console.log(result.text);

import { createTool } from "@mastra/core/tools";
import { z } from "zod";

const getWeather = createTool({
  id: "get-weather",
  description: "Get the current weather for a city.",
  inputSchema: z.object({
    city: z.string().describe("The city name"),
  }),
  outputSchema: z.object({
    temperature: z.number(),
    condition: z.string(),
  }),
  execute: async ({ context }) => {
    // call a weather API
    return { temperature: 22, condition: "Sunny" };
  },
});

// Attach to agent
const agent = new Agent({
  name: "WeatherAgent",
  model: openai("gpt-4o"),
  tools: { getWeather },
});

import { Workflow, Step } from "@mastra/core/workflows";
import { z } from "zod";

const fetchData = new Step({
  id: "fetchData",
  outputSchema: z.object({ content: z.string() }),
  execute: async ({ context }) => {
    return { content: "raw article text..." };
  },
});

const summarise = new Step({
  id: "summarise",
  inputSchema: z.object({ content: z.string() }),
  execute: async ({ context }) => {
    const text = context.getStepResult("fetchData")?.content ?? "";
    // call an LLM to summarise
    return { summary: text.slice(0, 100) + "..." };
  },
});

const pipeline = new Workflow({ name: "article-pipeline" })
  .step(fetchData)
  .then(summarise);

pipeline.commit();

const run = await pipeline.createRun();
const result = await run.start({});
console.log(result.results.summarise?.output?.summary);

const classify = new Step({
  id: "classify",
  execute: async ({ context }) => {
    return { intent: "complaint" }; // or "question", "praise"
  },
});

const handleComplaint = new Step({ id: "complaint", execute: async () => ({ reply: "We're sorry!" }) });
const handleQuestion  = new Step({ id: "question",  execute: async () => ({ reply: "Here's the answer." }) });

const flow = new Workflow({ name: "triage" })
  .step(classify)
  .branch([
    [async ({ context }) => context.getStepResult("classify")?.intent === "complaint", handleComplaint],
    [async ({ context }) => context.getStepResult("classify")?.intent === "question",  handleQuestion],
  ]);

flow.commit();

import { Memory } from "@mastra/memory";
import { LibSQLStore } from "@mastra/memory/storage";
import { LibSQLVector } from "@mastra/memory/vector/libsql";
import { Agent } from "@mastra/core/agent";
import { openai } from "@ai-sdk/openai";

const memory = new Memory({
  storage: new LibSQLStore({ url: "file:memory.db" }),
  vector: new LibSQLVector({ connectionUrl: "file:memory.db" }),
  options: {
    lastMessages: 20,            // include last 20 messages
    semanticRecall: { topK: 5 }, // retrieve 5 semantically relevant past messages
  },
});

const agent = new Agent({
  name: "MemoryAgent",
  model: openai("gpt-4o"),
  memory,
});

// Always pass threadId and resourceId for per-user isolation
const res = await agent.generate("Hello, I am Bob.", {
  threadId: "thread-001",
  resourceId: "user-42",
});

import { MastraVector } from "@mastra/rag";
import { openai } from "@ai-sdk/openai";

const vector = new MastraVector({ provider: "pg", connectionString: process.env.PG_URL! });

// Ingest documents
await vector.sync({
  indexName: "docs",
  vectors: [
    { id: "doc-1", vector: await embed("First document text"), metadata: { text: "First document text" } },
  ],
});

// Query at agent run-time
const results = await vector.query({
  indexName: "docs",
  queryVector: await embed(userQuery),
  topK: 5,
});

import { evaluate } from "@mastra/evals";
import { ToxicityMetric, SummarisationMetric } from "@mastra/evals/llm";
import { openai } from "@ai-sdk/openai";

const result = await evaluate({
  input: "Summarise the French Revolution.",
  output: agentSummary,
  metrics: [
    new ToxicityMetric(openai("gpt-4o")),
    new SummarisationMetric(openai("gpt-4o"), { referenceOutput: goldSummary }),
  ],
});

console.log(result.toxicity.score);    // 0–1
console.log(result.summarisation.score);

const agent = mastra.getAgent("assistant");

const stream = await agent.stream("Tell me a story about a robot.");

for await (const chunk of stream.textStream) {
  process.stdout.write(chunk);
}

import { createIntegration } from "@mastra/core/integration";
import { GithubIntegration } from "@mastra/github";
import { SlackIntegration } from "@mastra/slack";

const github = new GithubIntegration({ config: { PERSONAL_ACCESS_TOKEN: process.env.GH_TOKEN! } });
const slack  = new SlackIntegration({ config: { SLACK_BOT_TOKEN: process.env.SLACK_TOKEN! } });

const mastra = new Mastra({
  agents: { assistant },
  integrations: [github, slack],
});

// Mastra auto-generates tools from the integration's OpenAPI spec
const agent = new Agent({
  name: "DevAssistant",
  model: openai("gpt-4o"),
  tools: {
    ...await mastra.getIntegration("github").getTools(),
    ...await mastra.getIntegration("slack").getTools(),
  },
});

import { Mastra } from "@mastra/core";
import { OtelConfig } from "@mastra/core/telemetry";

const mastra = new Mastra({
  agents: { assistant },
  telemetry: new OtelConfig({
    serviceName: "my-agent-app",
    // Exports to any OTLP-compatible backend: Jaeger, Grafana, Langfuse
    exporter: { type: "otlp", url: "http://localhost:4318/v1/traces" },
    traceAll: true,   // trace every agent call and tool execution
  }),
});

const waitForApproval = new Step({
  id: "waitForApproval",
  execute: async ({ context, suspend }) => {
    const { ticketId } = context.getStepResult("createTicket")!;
    // Pause here — the workflow serialises its state and waits
    const approval = await suspend<{ approved: boolean }>({ ticketId });
    if (!approval.approved) throw new Error("Request rejected.");
    return { approved: true };
  },
});

// Resume later from an external event (webhook, UI button, etc.)
await run.resume({ stepId: "waitForApproval", payload: { approved: true } });
